module dig_stopwatch(    //Input Ports    input wire clk,        //Output Ports    output reg [7:0] second,    output reg [7:0] minute,    output reg hour_pulse,    output reg second_pulse,    output reg minute_pulse,    output reg beep);//Internal Clock Dividerreg [31:0] count;wire [31:0] COUNT_MAX = 5000000;assign count = count == COUNT_MAX? 0 : count + 1;//Second Counterreg [7:0] second_count;reg [7:0] second_max = 59;always @(posedge clk) begin    if (second_count == second_max) begin        second_count <= 0;        minute_pulse <= 1;    end else begin        second_count <= second_count + 1;    endend//Minute Counterreg [7:0] minute_count;reg [7:0] minute_max = 59;always @(posedge clk) begin    if (minute_count == minute_max) begin        minute_count <= 0;        hour_pulse <= 1;    end else begin        minute_count <= minute_count + 1;    endend//Hour Signalreg [2:0] hour_count;reg [2:0] HOUR_MAX = 5;always @(posedge clk) begin    if (hour_count == HOUR_MAX) begin        hour_count <= 0;    end else begin        hour_count <= hour_count + 1;    endend//Beep Mechanismalways @(*) begin    if (hour_pulse &&!second_pulse &&!minute_pulse) begin        beep <= 1;    end else begin        beep <= 0;    endendassign second = {4'b0, second_count};assign minute = {4'b0, minute_count};endmodule